export const NATION_FLAG_SLUGS = Object.keys(FLAGS)

/* Rendered once in the root document so the path data (USA alone is ~5KB)
   isn't serialized again for every flag instance on the page. */
export function NationFlagSprite() {
  return (
    <svg aria-hidden="true" width="0" height="0" className="absolute">
      {NATION_FLAG_SLUGS.map((slug) => (
        <g key={slug} id={`flag-${slug}`}>
          {FLAGS[slug]}
        </g>
      ))}
    </svg>
  )
}

const VARIANT_CLASS = {
  chip: 'flag-chip',
  wash: 'flag-wash',
  'wash-row': 'flag-wash-row',
  'wash-hero': 'flag-wash-hero',
} as const

export function NationFlag({
  slug,
  variant = 'chip',
  className = '',
}: {
  slug: string
  /** chip: inline beside the nation name; wash / wash-row: faint watermarks
      at pane and ledger-row scale. */
  variant?: keyof typeof VARIANT_CLASS
  className?: string
}) {
  if (!Object.hasOwn(FLAGS, slug)) return null
  return (
    <span
      aria-hidden="true"
      className={`${VARIANT_CLASS[variant]} ${className}`}
    >
      <svg
        viewBox={VIEWBOX}
        // washes cover their box (crop, never letterbox); chips keep the flag whole
        preserveAspectRatio={
          variant === 'chip' ? 'xMidYMid meet' : 'xMidYMid slice'
        }
        className="block h-full w-full"
      >
        <use href={`#flag-${slug}`} />
      </svg>
    </span>
  )
}
